import React, { useState, useEffect, useRef, useCallback, useMemo } from 'react';
import axios from 'axios';
import Navbar from "./components/Navbar";

const cacheBusqueda = {};

function App() {
  // Estados de Autenticación
  const [isLoggedIn, setIsLoggedIn] = useState(false);
  const [authMode, setAuthMode] = useState('login'); // 'login', 'register', 'recovery'
  const [usuario, setUsuario] = useState('');
  const [password, setPassword] = useState('');
  const [userRole, setUserRole] = useState('vendedor');
  const [nuevoRol, setNuevoRol] = useState('vendedor');

  // Estados de Datos
  const [view, setView] = useState('dashboard');
  const [stats, setStats] = useState({ total_productos: 0, valor_inventario: 0, bajo_stock: 0 });
  const [productos, setProductos] = useState([]);
  const [busqueda, setBusqueda] = useState('');
  const [loading, setLoading] = useState(false);

  // Estados de Formulario
  const [showForm, setShowForm] = useState(false);
  const [editMode, setEditMode] = useState(false);
  const [selectedId, setSelectedId] = useState(null);
  const [nuevoProd, setNuevoProd] = useState({ nombre: '', stock: '', precio_venta: '' });

  const abortControllerRef = useRef(null);

  // 1. CARGAR DATOS (Corregido: useCallback estable)
  const cargarDatos = useCallback(async () => {
    setLoading(true);
    try {
      const [resStats, resProds] = await Promise.all([
        axios.get('http://localhost:5000/api/stats'),
        axios.get('http://localhost:5000/api/productos')
      ]);
      setStats(resStats.data);
      setProductos(resProds.data);
    } catch (error) { console.error("Error cargando datos:", error); } 
    finally { setLoading(false); }
  }, []);

  useEffect(() => {
    if (isLoggedIn) {
      cargarDatos();
      const interval = setInterval(cargarDatos, 30000);
      return () => clearInterval(interval);
    }
  }, [isLoggedIn, cargarDatos]);

  // 2. BUSQUEDA (Corregido: useCallback para evitar warnings)
  const ejecutarBusqueda = useCallback(async (texto) => {
    if (texto.trim() === '') { cargarDatos(); return; }
    if (cacheBusqueda[texto]) { setProductos(cacheBusqueda[texto]); return; }
    if (abortControllerRef.current) abortControllerRef.current.abort();
    abortControllerRef.current = new AbortController();
    try {
      const res = await axios.get(`http://localhost:5000/api/productos/buscar?q=${texto}`, { 
        signal: abortControllerRef.current.signal 
      });
      cacheBusqueda[texto] = res.data;
      setProductos(res.data);
    } catch (err) { if (err.name !== 'CanceledError') console.error(err); }
  }, [cargarDatos]);

  const optimizadaBusqueda = useMemo(() => {
    const debounce = (fn, delay) => {
      let timeout;
      return (...args) => { clearTimeout(timeout); timeout = setTimeout(() => fn(...args), delay); };
    };
    return debounce(ejecutarBusqueda, 500);
  }, [ejecutarBusqueda]);

  const handleBusquedaChange = (e) => {
    setBusqueda(e.target.value);
    optimizadaBusqueda(e.target.value);
  };

  // 3. ACCIONES
  const handleLogin = async () => {
    try {
      const res = await axios.post('http://localhost:5000/api/login', { usuario, clave: password });
      if (res.data.success) { 
        setIsLoggedIn(true); 
        setUserRole(res.data.rol); 
      }
    } catch (e) { alert("Usuario o clave incorrectos"); }
  };


  const guardarProducto = async () => {
    const data = { nombre: nuevoProd.nombre, categoria: "General", stock: Number(nuevoProd.stock), precio_venta: Number(nuevoProd.precio_venta) };
    try {
      if (editMode) await axios.put(`http://localhost:5000/api/productos/${selectedId}`, data);
      else await axios.post('http://localhost:5000/api/productos', data);
      setShowForm(false); setEditMode(false); cargarDatos();
      setNuevoProd({ nombre: '', stock: '', precio_venta: '' });
    } catch (e) { alert("Error al guardar"); }
  };

  const eliminar = async (id) => {
    if (window.confirm("¿Eliminar este producto?")) {
      await axios.delete(`http://localhost:5000/api/productos/${id}`);
      cargarDatos();
    }
  };

  // --- VISTA LOGIN / REGISTRO / RECUPERACIÓN (ESTILO DARK APP) ---
  if (!isLoggedIn) {
    return (
      <div className="min-h-screen bg-[#bdc3c7] flex items-center justify-center p-4 font-sans transition-all">
        <div className="bg-[#2d333b] p-8 md:p-10 rounded-[40px] shadow-2xl w-full max-w-sm border border-gray-700">
          <div className="text-center mb-8">
            <h2 className="text-3xl font-bold text-white">
              {authMode === 'login' ? 'Bienvenido' : authMode === 'register' ? 'Registro' : 'Recuperar'}
            </h2>
            <div className="w-12 h-1 bg-[#00c984] mx-auto rounded-full mt-2"></div>
          </div>

          <div className="space-y-4">
            {/* Input Usuario (No sale en recuperación) */}
            {authMode !== 'recovery' && (
              <div className="relative">
                <i className="fas fa-user absolute left-4 top-4 text-[#00c984]"></i>
                <input className="w-full bg-[#444c56] text-white pl-12 pr-4 py-3 rounded-2xl outline-none focus:ring-2 focus:ring-[#00c984]" placeholder="Usuario" onChange={e => setUsuario(e.target.value)} />
              </div>
            )}

            {/* Input Email para Recuperación o Registro */}
            {(authMode === 'recovery' || authMode === 'register') && (
              <div className="relative">
                <i className="fas fa-envelope absolute left-4 top-4 text-[#00c984]"></i>
                <input className="w-full bg-[#444c56] text-white pl-12 pr-4 py-3 rounded-2xl outline-none" placeholder="Correo electrónico" />
              </div>
            )}

            {/* Selector de Rol en Registro */}
            {authMode === 'register' && (
              <div className="relative">
                <i className="fas fa-shield-alt absolute left-4 top-4 text-[#00c984]"></i>
                <select className="w-full bg-[#444c56] text-white pl-12 pr-4 py-3 rounded-2xl outline-none appearance-none" value={nuevoRol} onChange={e => setNuevoRol(e.target.value)}>
                  <option value="vendedor">Vendedor</option>
                  <option value="admin">Administrador</option>
                </select>
              </div>
            )}

            {/* Input Password */}
            {authMode !== 'recovery' && (
              <div className="relative">
                <i className="fas fa-lock absolute left-4 top-4 text-[#00c984]"></i>
                <input type="password" className="w-full bg-[#444c56] text-white pl-12 pr-4 py-3 rounded-2xl outline-none focus:ring-2 focus:ring-[#00c984]" placeholder="Contraseña" onChange={e => setPassword(e.target.value)} />
              </div>
            )}

            <div className="flex flex-col gap-3 pt-2">
              <button className="w-full bg-[#00c984] text-white font-bold py-4 rounded-2xl hover:brightness-110 active:scale-95 transition shadow-lg shadow-green-900/20" onClick={authMode === 'login' ? handleLogin : () => alert("Acción enviada...")}>
                {authMode === 'login' ? 'Entrar' : authMode === 'register' ? 'Crear Cuenta' : 'Enviar Instrucciones'}
              </button>

              <div className="flex justify-between text-xs text-gray-400 px-2">
                <span className="hover:text-[#00c984] cursor-pointer" onClick={() => setAuthMode(authMode === 'login' ? 'register' : 'login')}>
                  {authMode === 'login' ? 'Crear cuenta' : 'Ya tengo cuenta'}
                </span>
                {authMode === 'login' && (
                  <span className="hover:text-[#00c984] cursor-pointer" onClick={() => setAuthMode('recovery')}>¿Olvidaste tu clave?</span>
                )}
                {authMode === 'recovery' && (
                  <span className="hover:text-[#00c984] cursor-pointer" onClick={() => setAuthMode('login')}>Volver al login</span>
                )}
              </div>
            </div>
          </div>
        </div>
      </div>
    );
  }

  // --- VISTA DASHBOARD / INVENTARIO (ESTILO WALMART APP) ---
  return (
    <div className="min-h-screen bg-gray-50 pb-20 md:pb-0">
      <Navbar 
        setView={setView} 
        userRole={userRole} 
        logout={() => setIsLoggedIn(false)}
        busqueda={busqueda}
        handleBusquedaChange={handleBusquedaChange}
      />

      {loading && <div className="h-1 w-full bg-[#ffc220] fixed top-[112px] z-50 animate-pulse"></div>}

      <main className="max-w-7xl mx-auto p-4 md:p-8">
        {view === "dashboard" ? (
          <div className="space-y-6 animate-in fade-in slide-in-from-bottom-4 duration-500">
            <h2 className="text-xl md:text-2xl font-bold text-[#004f91]">Hola, {usuario} <span className="text-sm font-normal text-gray-500">({userRole})</span></h2>

            <div className="grid grid-cols-2 md:grid-cols-3 gap-3 md:gap-6">
              <div className="bg-white p-5 border rounded-3xl shadow-sm">
                <i className="fas fa-boxes text-[#0071ce] mb-2"></i>
                <p className="text-[10px] text-gray-400 font-bold uppercase tracking-wider">Productos</p>
                <p className="text-2xl md:text-3xl font-black">{stats.total_productos}</p>
              </div>
              <div className="bg-white p-5 border rounded-3xl shadow-sm">
                <i className="fas fa-exclamation-circle text-red-500 mb-2"></i>
                <p className="text-[10px] text-gray-400 font-bold uppercase tracking-wider">Bajo Stock</p>
                <p className="text-2xl md:text-3xl font-black text-red-500">{stats.bajo_stock}</p>
              </div>
              <div className="bg-white p-5 border rounded-3xl shadow-sm col-span-2 md:col-span-1">
                <i className="fas fa-wallet text-green-600 mb-2"></i>
                <p className="text-[10px] text-gray-400 font-bold uppercase tracking-wider">Valor Inventario</p>
                <p className="text-2xl md:text-3xl font-black text-green-600">${stats.valor_inventario.toLocaleString()}</p>
              </div>
            </div>
          </div>
        ) : (
          <div className="space-y-4 animate-in fade-in duration-300">
            <div className="flex justify-between items-center">
                <h2 className="text-xl font-bold text-gray-800 tracking-tight">Mi Inventario</h2>
                <button onClick={() => setShowForm(!showForm)} className="bg-[#0071ce] text-white px-5 py-2 rounded-full font-bold text-sm shadow-md active:scale-95 transition">
                    {showForm ? 'Cerrar' : '+ Agregar'}
                </button>
            </div>

            {showForm && (
              <div className="bg-white p-6 rounded-[30px] border-2 border-dashed border-gray-200 grid grid-cols-1 md:grid-cols-4 gap-3">
                  <input className="p-3 bg-gray-50 rounded-2xl outline-none focus:ring-2 focus:ring-[#0071ce]" placeholder="Producto" value={nuevoProd.nombre} onChange={e => setNuevoProd({...nuevoProd, nombre: e.target.value})} />
                  <input className="p-3 bg-gray-50 rounded-2xl outline-none" placeholder="Stock" type="number" value={nuevoProd.stock} onChange={e => setNuevoProd({...nuevoProd, stock: e.target.value})} />
                  <input className="p-3 bg-gray-50 rounded-2xl outline-none" placeholder="Precio" type="number" value={nuevoProd.precio_venta} onChange={e => setNuevoProd({...nuevoProd, precio_venta: e.target.value})} />
                  <button onClick={guardarProducto} className="bg-[#ffc220] text-[#004f91] font-bold rounded-2xl py-3 hover:brightness-105 active:scale-95 transition">GUARDAR</button>
              </div>
            )}

            <div className="bg-white border rounded-[30px] overflow-hidden shadow-sm overflow-x-auto">
                <table className="w-full text-left border-collapse">
                  <thead className="bg-gray-50 border-b">
                      <tr className="text-[10px] text-gray-400 uppercase font-bold tracking-widest">
                        <th className="p-4">Producto</th>
                        <th className="p-4">Stock</th>
                        <th className="p-4">Precio</th>
                        <th className="p-4 text-center">Acciones</th>
                      </tr>
                  </thead>
                  <tbody className="divide-y divide-gray-100">
                      {productos.map(p => (
                      <tr key={p.id} className="hover:bg-blue-50/30 transition group">
                          <td className="p-4">
                            <p className="font-bold text-[#004f91]">{p.nombre}</p>
                            <p className="text-[10px] text-gray-400">ID: {p.id}</p>
                          </td>
                          <td className="p-4">
                            <span className={`px-3 py-1 rounded-full text-[10px] font-black ${p.stock < 10 ? 'bg-red-100 text-red-600' : 'bg-green-100 text-green-600'}`}>
                                {p.stock} UNID.
                            </span>
                          </td>
                          <td className="p-4 font-black text-sm">${p.precio_venta}</td>
                          <td className="p-4 text-center">
                            <div className="flex justify-center gap-3">
                              <button onClick={() => { setSelectedId(p.id); setNuevoProd(p); setEditMode(true); setShowForm(true); }} className="text-blue-500 opacity-50 group-hover:opacity-100"><i className="fas fa-edit"></i></button>
                              <button onClick={() => eliminar(p.id)} className="text-red-400 opacity-50 group-hover:opacity-100"><i className="fas fa-trash"></i></button>
                            </div>
                          </td>
                      </tr>
                      ))}
                  </tbody>
                </table>
            </div>
          </div>
        )}
      </main>
    </div>
  );
}

export default App;
